            negatives.append(-num)
        else:
            positives.append(num)

    # Radix sort for positives
    if positives:
        max_val = max(positives)
        exp = 1
        while max_val // exp > 0:
            # Counting sort by digit
            count = [0] * 10
            for num in positives:
                count[(num // exp) % 10] += 1

            for i in range(1, 10):
                count[i] += count[i - 1]

            output = [0] * len(positives)
            for i in range(len(positives) - 1, -1, -1):
                digit = (positives[i] // exp) % 10
                output[count[digit] - 1] = positives[i]
                count[digit] -= 1

            positives = output
            exp *= 10

    # Radix sort for negatives (stored as positive values)
    if negatives:
        max_val = max(negatives)
        exp = 1
        while max_val // exp > 0:
            count = [0] * 10
            for num in negatives:
                count[(num // exp) % 10] += 1

            for i in range(1, 10):
                count[i] += count[i - 1]

            output = [0] * len(negatives)
            for i in range(len(negatives) - 1, -1, -1):
                digit = (negatives[i] // exp) % 10
                output[count[digit] - 1] = negatives[i]
                count[digit] -= 1

            negatives = output
            exp *= 10

        # Convert back to negative and reverse for descending order
        negatives = [-num for num in reversed(negatives)]

    return negatives + positives

